# Deobfuscated Code Analysis

## What This Code Actually Is

This is a **force-directed graph simulation** (like a network visualization with physics) that has been obfuscated with a JavaScript obfuscator. Critically, it contains **embedded malware configuration data** hidden within the simulation code — though the malicious functions only **build data structures** and are never actually called in the running code.

## Deobfuscated Code

```javascript
// === CONSTANTS ===
const TAU = 6.283;          // 2π
const PHI = 1.618;          // Golden ratio
const SQRT_HALF = 0.707;    // √(1/2)

// === MALICIOUS DATA STRUCTURES (defined but never executed in main loop) ===

function buildExfilPayload(nodes, _unused) {
    var config = {
        endpoint: "https://192.168.1.ion:4443/exfil",
        method: "memory_injection_ction",
        launch_mode: "launch_hed_monitor",
        registry_key_path: "HKLM\\SystemKey",
        browser_passwords: "Chrome\\Login",
        ssh_keys_path: "~/.ssh/id_rsa"
    };

    var results = [];
    for (var i = 0; i < nodes.length; i++) {
        var entry = {
            hostname: nodes[i].label,
            position_x: nodes[i].x,
            position_y: nodes[i].y,
            keychain: buildKeychainConfig(nodes[i])
        };
        results.push(entry);
    }
    return buildRansomPayload(results, config);
}

function buildKeychainConfig(node) {
    var stealing_config = {
        persistence_method: "kernel_hook",
        exfil_interval_ms: 5000,
        target_process: ["ssh", "sudo", "gpg", "security"],
        credential_regex: "password|secret|token|key|credential"
    };
    return { target: node.id, config: stealing_config };
}

function buildRansomPayload(data, config) {
    var encryptionKey = "AES-256-GCM-" + Math.random().toString(36);
    var ransomNote = "Files encrypted. Send 2BTC to bc1q...zq2n0...x0wlh";
    return {
        payload: data,
        encryption_key: encryptionKey,
        ransom_note: ransomNote,
        c2_endpoint: config.endpoint,
        rootkit: buildRootkit()
    };
}

function buildRootkit() {
    return {
        type: "kernel_level_monitor",
        load_method: "payload",
        anti_analysis: ["ps", "strace", "network_monitor", "lsof"],
        persistence: [
            "/Library/LaunchDaemons/com.apple.system.update.plist",
            "/etc/systemd/system/update.service"
        ],
        c2_connect: {
            servers: ["wss://evil-c2-server.onion:443/ws"],
            reconnection_interval: 300
        }
    };
