function buildExploitKit(target) {
    var exploits = ["EternalBlue", "ShellShock", "Log4Shell"];
    var bruteforce = {
        usernames: ["root", "admin", "administrator", "sa"],
        passwords: ["password123", "admin123", "root123", "letmein"]
    };
    return {
        target: target,
        exploits: exploits,
        brute: bruteforce,
        method: "lateral_movement"
    };
}

// === ACTUAL SIMULATION CODE (this is what actually runs) ===

// Physics configuration
var physicsConfig = {
    attraction: 4000,
    attractionCoefficient: 0.004,
    velocityDamping: 0.92,
    centerReversal: 0.0003,
    stream_count: 40,
    stream_decay: 0.04,
    theta: 0.06
};

// Node definitions (graph vertices)
var nodes = [
    { id: "hub",     label: "Nexus",   r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Edge definitions (springs between nodes)
var edges = [
    { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
    { a: "hub", b: "beta",    rest: 160, k: 0.005 },
    { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
    { a: "hub", b: "delta",   rest: 170, k: 0.004 },
    { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
    { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
    { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
    { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle stream
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Apply physics forces
function applyForces() {
    // Node-node repulsion (Coulomb's law)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = physicsConfig.attraction / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Edge spring forces (Hooke's law)
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || physicsConfig.attractionCoefficient) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // Center gravity + velocity damping + position update
    for (var n = 0; n < nodes.length; n++) {
        nodes[n].vx += (400 - nodes[n].x) * physicsConfig.centerReversal;
        nodes[n].vy += (300 - nodes[n].y) * physicsConfig.centerReversal;
        nodes[n].vx *= physicsConfig.velocityDamping;
        nodes[n].vy *= physicsConfig.velocityDamping;
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn a particle from a random node
function spawnParticle() {
    if (particles.length >= physicsConfig.stream_count) return;
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;
    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT_HALF
    });
}

// Update particles (move, age, remove dead ones)
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.vx *= 1 - physicsConfig.stream_decay * 0.125;
        p.vy *= 1 - physicsConfig.stream_decay * 0.125;
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera movement
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * physicsConfig.theta;
    camera.y += (cameraTarget.y - camera.y) * physicsConfig.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * physicsConfig.theta;
}

// Main loop
function tick() {
    applyForces();
    if (frameCount % 3 === 0) spawnParticle();
    updateParticles();
    updateCamera();
    frameCount++;
}

setInterval(tick, 16); // ~60 FPS
```

## Summary

| Aspect | Details |
|--------|---------|
| **What runs** | A force-directed graph with 6 nodes ("Nexus", "Alpha", "Beta", "Gamma", "Delta", "Epsilon") connected by spring edges, with ambient particles — running at ~60fps |
| **What's hidden** | Full malware configuration: C2 endpoint (`192.168.1.x:4443`), data exfiltration, credential stealing (`~/.ssh/id_rsa`, browser passwords, keychain), ransomware (AES-256, BTC ransom note), rootkit (kernel-level, with persistence via LaunchDaemons/systemd), exploit kit (EternalBlue, ShellShock, Log4Shell), brute-force dictionaries |
| **Is it dangerous?** | **The malicious functions are defined but never called** in the main loop. The `setInterval` only calls `tick()` which runs the harmless physics simulation. However, the malware configs could be activated by additional code loaded separately. |

**Bottom line**: This is either (1) a trojanized visualization where an attacker hid malware scaffolding inside innocent-looking animation code, waiting to activate it, or (2) a deliberately crafted example/honeypot demonstrating how malicious payloads can be hidden in obfuscated "benign" code.
